sql:
SELECT c.customer_id, c.customer_number, p.policy_type
FROM customers c
LEFT JOIN policies p ON c.customer_id = p.customer_id;

external_knowledge:
- 'residents' refers to customers;
- 'keys to their home' symbolizes policy numbers;
- 'depth of their roots' metaphorically represents customer lifetime value;
- 'magic number five' is the multiplier used in the calculation of total lifetime value.

sql:
SELECT DISTINCT customers.customer_id, customers.customer_number, customers.state, policies.policy_id, policies.policy_type
FROM customers
JOIN policies ON customers.customer_id = policies.customer_id;

external_knowledge:
- "seafarers" refers to customers;
- "stormy seas of high claim amounts" refers to claims with amounts greater than 5000;
- "significant yearly premiums" refers to policies where the yearly premium, calculated as `monthly_premium * 12`, is more than 10,000;
- "golden threshold of 5000" refers to the minimum claim amount of 5000.

sql:
SELECT c.customer_id, c.customer_number, c.state, c.gender, c.education, c.lifetime_value, c.income, c.date_of_birth, c.marital_status, c.number_of_dependents, c.address, c.phone_number, c.email, c.referral_source, c.first_interaction_date
FROM customers c
WHERE EXISTS (SELECT 1 FROM complaints WHERE customer_id = c.customer_id);

SELECT claim_id, outstanding_amount
FROM claims
WHERE outstanding_amount > (SELECT AVG(outstanding_amount) FROM claims);

SELECT AVG(c.income) AS Average_Income, SUM(c.lifetime_value) AS Total_Lifetime_Value
FROM customers c
JOIN complaints co ON c.customer_id = co.customer_id;

external_knowledge:
- 'substantial number of policies' refers to agents who have sold more than 10 policies;
- 'business car policy' corresponds to the 'Corporate Auto' policy type;
- 'managed to sell' implies the number of policies sold by an agent;
- 'clients' refer to customers associated with an agent.

sql:
SELECT policy_id, policy_type, monthly_premium
FROM policies
WHERE monthly_premium = (
    SELECT MAX(monthly_premium)
    FROM policies
);
